/*
 * logf() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly logf  (test_logf_opt.elf)
 *   2. Linked with toolchain's default logf        (test_logf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

#ifdef EN_PERF
static volatile float g_acc;
#endif

static void emit(float x)
{
#ifdef EN_PERF
    volatile float vx = x;   /* prevent constant-folding of literal arguments */
    g_acc += logf(vx);
#else
    float r = logf(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
#endif
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

/* ------------------------------------------------------------------ */
/* test_representative_100: 100 representative inputs for logf        */
/* ------------------------------------------------------------------ */

#ifndef EN_PERF
static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values + domain errors (9) --- */
    emit(0.0f);                      /* log(+0) = -Inf */
    emit(-0.0f);                     /* log(-0) = -Inf */
    emit_u(0x7fc00000u);             /* qNaN */
    emit_u(0x7f800001u);             /* sNaN */
    emit_u(0xffc00000u);             /* -qNaN */
    emit_u(0x7f800000u);             /* +Inf -> +Inf */
    emit_u(0xff800000u);             /* -Inf -> NaN (domain error) */
    emit(-1.0f);                     /* negative input -> NaN */
    emit(-1.0e10f);                  /* large negative -> NaN */

    /* --- Section 2: Subnormal values (6) --- */
    emit_u(0x00000001u);             /* min positive subnormal: 2^-149 */
    emit_u(0x00400000u);             /* mid positive subnormal */
    emit_u(0x007fffffu);             /* max positive subnormal: just below FLT_MIN */
    emit_u(0x80000001u);             /* min negative subnormal -> NaN */
    emit_u(0x80400000u);             /* mid negative subnormal -> NaN */
    emit_u(0x807fffffu);             /* max negative subnormal -> NaN */

    /* --- Section 3: Normal boundary values (5) --- */
    emit(FLT_MIN);                   /* smallest positive normal: 2^-126 = 0x00800000 */
    emit_u(0x00800001u);             /* one ULP above FLT_MIN */
    emit_u(0x7f7ffffeu);             /* one ULP below FLT_MAX */
    emit(FLT_MAX);                   /* largest finite float: 0x7f7fffff */
    emit(-FLT_MIN);                  /* negative of smallest normal -> NaN */

    /* --- Section 4: Near 1.0 ULP neighbors (8) --- */
    emit_u(0x3f7fffffu);             /* one ULP below 1.0 */
    emit(1.0f);                      /* log(1.0) = 0.0 exactly */
    emit_u(0x3f800001u);             /* one ULP above 1.0 */
    emit_u(0x3f7ffff0u);             /* a few ULPs below 1.0 */
    emit_u(0x3f800010u);             /* a few ULPs above 1.0 */
    emit_u(0x3f7fff00u);             /* more ULPs below 1.0 */
    emit_u(0x3f800100u);             /* more ULPs above 1.0 */
    emit_u(0x3f7fe000u);             /* well below 1.0 but close */

    /* --- Section 5: Exponent switching points (6) --- */
    emit_u(0x3f000000u);             /* 0.5 exactly */
    emit_u(0x3effffffu);             /* one ULP below 0.5 */
    emit_u(0x3f000001u);             /* one ULP above 0.5 */
    emit_u(0x40000000u);             /* 2.0 exactly */
    emit_u(0x3fffffffu);             /* one ULP below 2.0 */
    emit_u(0x40000001u);             /* one ULP above 2.0 */

    /* --- Section 6: Log-specific mathematical constants (14) --- */
    emit_u(0x402df854u);             /* e ~ 2.71828: log(e) = 1.0 */
    emit_u(0x40ebc84au);             /* e^2 ~ 7.389: log(e^2) = 2.0 */
    emit_u(0x3f317218u);             /* ln2 ~ 0.6931: log(ln2) */
    emit_u(0x40135d8eu);             /* ln10 ~ 2.3026: log(ln10) */
    emit_u(0x3eb8aa3bu);             /* 1/ln2 = log2(e) ~ 1.4427 */
    emit_u(0x3f3a4320u);             /* 1/ln10 = log10(e) ~ 0.4343 */
    emit(0.5f);                      /* log(0.5) = -ln2 */
    emit(2.0f);                      /* log(2.0) = ln2 */
    emit(4.0f);                      /* log(4.0) = 2*ln2 */
    emit(8.0f);                      /* log(8.0) = 3*ln2 */
    emit(16.0f);                     /* log(16.0) = 4*ln2 */
    emit(10.0f);                     /* log(10.0) = ln10 */
    emit(100.0f);                    /* log(100.0) = 2*ln10 */
    emit_u(0x3f3504f3u);             /* sqrt(2) ~ 1.41421: log(sqrt(2)) = ln2/2 */

    /* --- Section 7: Near zero (very small positive, large negative result) (8) --- */
    emit(1.0e-10f);                  /* small but not subnormal */
    emit(1.0e-20f);                  /* very small */
    emit(1.0e-30f);                  /* near subnormal territory */
    emit_u(0x00c00000u);             /* small subnormal-adjacent normal */
    emit(1.0e-7f);                   /* 10^-7 */
    emit(1.0e-5f);                   /* 10^-5 */
    emit(1.0e-3f);                   /* 10^-3 */
    emit(1.0e-1f);                   /* 0.1 */

    /* --- Section 8: Near 1.0 polynomial stress (8) --- */
    emit(1.0f + 1.0e-5f);            /* 1.0 + small epsilon */
    emit(1.0f - 1.0e-5f);            /* 1.0 - small epsilon */
    emit(1.0f + 1.0e-6f);            /* 1.0 + tiny epsilon */
    emit(1.0f - 1.0e-6f);            /* 1.0 - tiny epsilon */
    emit(0.999999940f);              /* nearest float below 1.0 */
    emit(1.000000060f);              /* nearest float above 1.0 */
    emit_u(0x3f800002u);             /* 1.0 + 2 ULPs */
    emit_u(0x3f7ffffeu);             /* 1.0 - 2 ULPs */

    /* --- Section 9: Large arguments (8) --- */
    emit(1.0e10f);                   /* large: log is ~23.03 */
    emit(1.0e20f);                   /* very large: log is ~46.05 */
    emit(1.0e30f);                   /* near FLT_MAX range */
    emit(1.0e35f);                   /* approaching FLT_MAX */
    emit_u(0x7f7fffffu);             /* FLT_MAX = 3.4028235e38 */
    emit(1000.0f);                   /* log(1000) = 3*ln10 */
    emit(1.0e6f);                    /* log(1e6) = 6*ln10 */
    emit(3.0f);                      /* log(3.0) = ln3 */

    /* --- Section 10: Hard cases and ULP stress (28) --- */
    /* Powers of 2 up and down */
    emit(0.0625f);                   /* 2^-4 */
    emit(0.125f);                    /* 2^-3 */
    emit(0.25f);                     /* 2^-2 */
    emit(32.0f);                     /* 2^5 */
    emit(64.0f);                     /* 2^6 */
    emit(128.0f);                    /* 2^7 */
    emit(256.0f);                    /* 2^8 */
    emit(512.0f);                    /* 2^9 */
    /* Powers of 10 */
    emit(0.01f);                     /* 10^-2 */
    emit(0.1f);                      /* 10^-1 */
    emit(1000.0f);                   /* 10^3: duplicate with S9? No - already in S9 as 1000 */
    /* ULP neighbors of key values */
    emit_u(0x3e800000u);             /* 0.25: 2^-2 */
    emit_u(0x3e800001u);             /* one ULP above 0.25 */
    emit_u(0x3e7fffffu);             /* one ULP below 0.25 */
    emit_u(0x40800000u);             /* 4.0: 2^2 */
    emit_u(0x40800001u);             /* one ULP above 4.0 */
    emit_u(0x407fffffu);             /* one ULP below 4.0 */
    /* Input that causes cancellation near log(1) */
    emit_u(0x3f800003u);             /* 1.0 + 3 ULPs */
    emit_u(0x3f7ffffd u);            /* 1.0 - 3 ULPs */
    /* Values that stress the polynomial approximation [0.5, 1.0] */
    emit_u(0x3f400000u);             /* 0.75 */
    emit_u(0x3f200000u);             /* 0.625 */
    emit_u(0x3f600000u);             /* 0.875 */
    emit_u(0x3fc00000u);             /* 1.5 */
    emit_u(0x3fa00000u);             /* 1.25 */
    emit_u(0x3fe00000u);             /* 1.75 */
    /* Negative values near -1 (all domain errors -> NaN) */
    emit(-0.5f);                     /* negative input -> NaN */
    emit_u(0xbf800001u);             /* -1.0 - 1 ULP -> NaN */
    emit_u(0xbf7fffffu);             /* -1.0 + 1 ULP (magnitude) -> NaN */
    emit(-2.0f);                     /* negative -> NaN */
}
#endif /* !EN_PERF */

/* ------------------------------------------------------------------ */

#ifdef EN_PERF
